prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelId ?start ?startName ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "2b18c5f00a5a46159c6cb6a3e2bc79e9")

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo ;
         bbo:name ?startName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Aufrtag")))

  FILTER EXISTS {
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?start ?startName ?task ?taskName ?taskId WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId ;
         tai:belongsTo ?org .
  FILTER(?modelId = "2b18c5f00a5a46159c6cb6a3e2bc79e9")

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?start a bboExt:StartEvent ;
         tai:belongsTo ?choreo ;
         bbo:name ?startName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName ;
        bbo:id ?taskId .

  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("auftrag")))
} 
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2b18c5f00a5a46159c6cb6a3e2bc79e9" ;
         tai:belongsTo ?org .

  ?choreo tai:belongsTo ?model ;
          a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(?taskName != "")
}
ORDER BY ?choreoName ?taskName
LIMIT 25
